   484→#[test]
   485→#[cfg(unix)]
   486→fn test_dev_random() {
   487→    #[cfg(any(target_os = "linux", target_os = "android"))]
   488→    const DEV_RANDOM: &str = "/dev/urandom";
   489→
   490→    #[cfg(not(any(target_os = "linux", target_os = "android")))]
   491→    const DEV_RANDOM: &str = "/dev/random";
   492→
   493→    let mut proc = new_ucmd!()
   494→        .set_stdout(Stdio::piped())
   495→        .args(&[DEV_RANDOM])
   496→        .run_no_wait();
   497→
   498→    proc.make_assertion_with_delay(100).is_alive();
   499→    let buf = proc.stdout_exact_bytes(2048);
   500→    let num_zeroes = buf.iter().fold(0, |mut acc, &n| {
   501→        if n == 0 {
   502→            acc += 1;
   503→        }
   504→        acc
   505→    });
   506→    // The probability of more than 512 zero bytes is essentially zero if the
   507→    // output is truly random.
   508→    assert!(num_zeroes < 512);
   509→    proc.kill();
   510→}
