   563→#[test]
   564→#[cfg(unix)]
   565→#[ignore = ""]
   566→fn test_domain_socket() {
   567→    use std::io::prelude::*;
   568→    use std::os::unix::net::UnixListener;
   569→    use std::sync::{Arc, Barrier};
   570→    use std::thread;
   571→
   572→    let dir = tempfile::Builder::new()
   573→        .prefix("unix_socket")
   574→        .tempdir()
   575→        .expect("failed to create dir");
   576→    let socket_path = dir.path().join("sock");
   577→    let listener = UnixListener::bind(&socket_path).expect("failed to create socket");
   578→
   579→    // use a barrier to ensure we don't run cat before the listener is setup
   580→    let barrier = Arc::new(Barrier::new(2));
   581→    let barrier2 = Arc::clone(&barrier);
   582→
   583→    let thread = thread::spawn(move || {
   584→        let mut stream = listener.accept().expect("failed to accept connection").0;
   585→        barrier2.wait();
   586→        stream
   587→            .write_all(b"a\tb")
   588→            .expect("failed to write test data");
   589→    });
   590→
   591→    let child = new_ucmd!().args(&[socket_path]).run_no_wait();
   592→    barrier.wait();
   593→    child.wait().unwrap().stdout_is("a\tb");
   594→
   595→    thread.join().unwrap();
