fn write_to_end<W: Write>(in_buf: &[u8], writer: &mut W) -> usize {
    // using memchr2 significantly improves performances
    match memchr2(b'\n', b'\r', in_buf) {
        Some(p) => {
            if let Err(e) = writer.write_all(&in_buf[..p]) {
                if e.kind() != std::io::ErrorKind::BrokenPipe {
                    std::process::exit(1);
                }
                // Ignore broken pipe errors - they're expected when the reader closes
                return p;
            }
            p
        }
        None => {
            if let Err(e) = writer.write_all(in_buf) {
                if e.kind() != std::io::ErrorKind::BrokenPipe {
                    std::process::exit(1);
                }
                // Ignore broken pipe errors - they're expected when the reader closes
                return in_buf.len();
            }
            in_buf.len()
        }
    }
}

