fn write_end_of_line<W: Write>(
    writer: &mut W,
    end_of_line: &[u8],
    is_interactive: bool,
) -> CatResult<()> {
    if let Err(e) = writer.write_all(end_of_line) {
        if e.kind() == std::io::ErrorKind::BrokenPipe {
            return Ok(());
        }
        return Err(e.into());
    }
    if is_interactive {
        if let Err(e) = writer.flush() {
            if e.kind() != std::io::ErrorKind::BrokenPipe {
                return Err(e.into());
            }
            // Ignore broken pipe errors
        }
    }
    Ok(())
}

