#[cfg(unix)]
use std::os::fd::AsFd;
#[cfg(unix)]
use std::os::unix::fs::FileTypeExt;
#[cfg(unix)]
use std::os::unix::net::UnixStream;

use clap::{Arg, ArgAction, Command};
use memchr::memchr2;
use thiserror::Error;
use uucore::display::Quotable;
use uucore::error::UResult;
